/// Grace period before an `Earliest` resolve is allowed to spawn an empty payload fallback.
#[arg(long = "builder.empty-payload-grace", value_parser = parse_duration_from_secs_or_ms, default_value = "200ms", value_name = "DURATION")]
pub empty_payload_grace: Duration,

impl Default for PayloadBuilderArgs {
    fn default() -> Self {
        Self {
            empty_payload_grace: Duration::from_millis(200),
            /* ... */
        }
    }
}

fn empty_payload_grace(&self) -> Duration {
    self.empty_payload_grace
}

/// Maximum block size in bytes. If not specified, no size limit is enforced.
#[arg(long = "builder.max-block-size", value_parser = RangedU64ValueParser::<usize>::new().range(1..), value_name = "BYTES")]
pub max_block_size_bytes: Option<usize>,

impl Default for PayloadBuilderArgs {
    fn default() -> Self {
        Self { max_block_size_bytes: None, /* ... */ }
    }
}

fn max_block_size_bytes(&self) -> Option<usize> {
    self.max_block_size_bytes
}

use crate::{cli::config::PayloadBuilderConfig, version::default_extra_data};

impl TypedValueParser for ExtraDataValueParser {
    fn parse_ref(/* ... */) -> Result<Self::Value, clap::Error> {
        let val = value.to_str().ok_or_else(|| clap::Error::new(clap::error::ErrorKind::InvalidUtf8))?;
        Ok(val.to_string())
    }
}

#[test]
fn test_large_extra_data() {
    let extra_data = "x".repeat(1024);
    let args = CommandParser::<PayloadBuilderArgs>::try_parse_from([
        "reth",
        "--builder.extradata",
        extra_data.as_str(),
    ]).unwrap().args;
    assert_eq!(args.extra_data, extra_data);
}
